import { detectPackageManager, PackageManager } from '../detect';
import { spawnPM, SpawnResult } from '../utils/spawn';
import { isJsonMode, printJSON, printHuman } from '../utils/output';

function buildArgs(pm: PackageManager, packages: string[]): string[] {
    switch (pm) {
        case 'npm': return ['uninstall', ...packages];
        case 'yarn': return ['remove', ...packages];
        case 'pnpm': return ['remove', ...packages];
        case 'bun': return ['remove', ...packages];
    }
}

export async function remove(
    packages: string[],
    options: { json?: boolean }
): Promise<{ exitCode: number; pm: string; command: string }> {
    if (packages.length === 0) {
        printHuman('No packages specified. Usage: bi rm <pkg...>', 'error');
        return { exitCode: 1, pm: '', command: '' };
    }

    const detection = detectPackageManager();
    const args = buildArgs(detection.pm, packages);
    const command = `${detection.pm} ${args.join(' ')}`;

    printHuman(`Running: ${command}`, 'info');

    const result: SpawnResult = await spawnPM(detection.pm, args, {
        stdio: isJsonMode() ? 'pipe' : 'inherit',
    });

    const output = { exitCode: result.exitCode, pm: detection.pm, command };

    if (isJsonMode()) {
        printJSON(output);
    } else if (result.exitCode === 0) {
        printHuman('Done!', 'success');
    }

    return output;
}
